// ============================================
// COMPONENT
// ============================================
function ParticleEditor() {
    var canvasRef = useRef(null);
    var particlesRef = useRef([]);
    var spawnAccRef = useRef(0);
    var lastTimeRef = useRef(null);
    var animFrameRef = useRef(null);
    var draggingRef = useRef(false);

    var [config, setConfig] = useState(deepClone(DEFAULT_CONFIG));
    var [emitterPos, setEmitterPos] = useState({ x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2 });
    var [particleCount, setParticleCount] = useState(0);
    var [paused, setPaused] = useState(false);
    var [showExport, setShowExport] = useState(false);
    var [exportJSON, setExportJSON] = useState("");

    // -- TEMPLATE STATE --
    var [templates, setTemplates] = useState(STARTER_TEMPLATES.map(deepClone));
    var [activeTemplateIndex, setActiveTemplateIndex] = useState(null);
    var [unsavedChanges, setUnsavedChanges] = useState(false);

    var configRef = useRef(config);
    var emitterPosRef = useRef(emitterPos);
    var pausedRef = useRef(paused);

    useEffect(function() { configRef.current = config; }, [config]);
    useEffect(function() { emitterPosRef.current = emitterPos; }, [emitterPos]);
    useEffect(function() { pausedRef.current = paused; }, [paused]);

    // ---- TEMPLATE ACTIONS ----

    function handleLoadTemplate(index) {
        var tpl = templates[index];
        setConfig(deepClone(tpl));
        setActiveTemplateIndex(index);
        setUnsavedChanges(false);
        // Clear particles for clean preview
        particlesRef.current = [];
        spawnAccRef.current = 0;
    }

    function handleSaveTemplate() {
        var name = config.name || "untitled";
        var newTemplate = deepClone(config);
        newTemplate.name = name;

        if (activeTemplateIndex !== null) {
            // Overwrite existing
            setTemplates(function(prev) {
                var next = prev.map(deepClone);
                next[activeTemplateIndex] = newTemplate;
                return next;
            });
            setUnsavedChanges(false);
        } else {
            // Save as new
            setTemplates(function(prev) {
                var next = prev.map(deepClone);
                next.push(newTemplate);
                return next;
            });
            setActiveTemplateIndex(templates.length);
            setUnsavedChanges(false);
        }
    }

    function handleSaveAsNew() {
        var newTemplate = deepClone(config);
        var baseName = config.name || "untitled";
        newTemplate.name = baseName + "_copy";
        setTemplates(function(prev) {
            var next = prev.map(deepClone);
            next.push(newTemplate);
            return next;
        });
        setConfig(function(prev) {
            return Object.assign({}, prev, { name: newTemplate.name });
        });
        setActiveTemplateIndex(templates.length);
        setUnsavedChanges(false);
        particlesRef.current = [];
        spawnAccRef.current = 0;
    }

    function handleDuplicateTemplate(index) {
        var source = templates[index];
        var dupe = deepClone(source);
        dupe.name = source.name + "_copy";
        setTemplates(function(prev) {
            var next = prev.map(deepClone);
            next.push(dupe);
            return next;
        });
    }

    function handleDeleteTemplate(index) {
        setTemplates(function(prev) {
            var next = prev.filter(function(_, i) { return i !== index; });
            return next;
        });
        if (activeTemplateIndex === index) {
            setActiveTemplateIndex(null);
            setUnsavedChanges(false);
        } else if (activeTemplateIndex !== null && activeTemplateIndex > index) {
            setActiveTemplateIndex(activeTemplateIndex - 1);
        }
    }

    function handleNewFromScratch() {
        setConfig(deepClone(DEFAULT_CONFIG));
        setActiveTemplateIndex(null);
        setUnsavedChanges(false);
        particlesRef.current = [];
        spawnAccRef.current = 0;
    }

    // ---- MAIN LOOP ----

    var tick = useCallback(function(timestamp) {
        var canvas = canvasRef.current;
        if (!canvas) return;
        var ctx = canvas.getContext("2d");

        if (!lastTimeRef.current) lastTimeRef.current = timestamp;
        var dt = Math.min((timestamp - lastTimeRef.current) / 1000, 0.05);
        lastTimeRef.current = timestamp;

        var cfg = configRef.current;
        var pos = emitterPosRef.current;
        var particles = particlesRef.current;

        ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
        drawGrid(ctx, CANVAS_WIDTH, CANVAS_HEIGHT);

        if (!pausedRef.current) {
            spawnAccRef.current += cfg.spawnRate * dt;
            var toSpawn = Math.floor(spawnAccRef.current);
            spawnAccRef.current -= toSpawn;

            for (var i = 0; i < toSpawn; i++) {
                if (particles.length < MAX_PARTICLES) {
                    particles.push(createParticle(pos.x, pos.y, cfg));
                }
            }

            for (var j = particles.length - 1; j >= 0; j--) {
                updateParticle(particles[j], dt, cfg.gravity);
                if (!particles[j].alive) {
                    particles.splice(j, 1);
                }
            }
        }

        for (var k = 0; k < particles.length; k++) {
            drawParticle(ctx, particles[k], cfg);
        }

        drawEmitterHandle(ctx, pos.x, pos.y, true);

        setParticleCount(particles.length);
        animFrameRef.current = requestAnimationFrame(tick);
    }, []);

    useEffect(function() {
        animFrameRef.current = requestAnimationFrame(tick);
        return function() {
            if (animFrameRef.current) cancelAnimationFrame(animFrameRef.current);
        };
    }, [tick]);

    // ---- MOUSE HANDLERS ----

    function handleMouseDown(e) {
        var rect = canvasRef.current.getBoundingClientRect();
        var mx = e.clientX - rect.left;
        var my = e.clientY - rect.top;
        var pos = emitterPosRef.current;
        var dx = mx - pos.x;
        var dy = my - pos.y;
        if (Math.abs(dx) < EMITTER_HANDLE_SIZE && Math.abs(dy) < EMITTER_HANDLE_SIZE) {
            draggingRef.current = true;
        }
    }

    function handleMouseMove(e) {
        if (!draggingRef.current) return;
        var rect = canvasRef.current.getBoundingClientRect();
        var mx = Math.max(0, Math.min(CANVAS_WIDTH, e.clientX - rect.left));
        var my = Math.max(0, Math.min(CANVAS_HEIGHT, e.clientY - rect.top));
        setEmitterPos({ x: Math.round(mx), y: Math.round(my) });
    }

    function handleMouseUp() {
        draggingRef.current = false;
    }

    // ---- CONFIG CHANGE ----

    function handleParamChange(key, value) {
        setConfig(function(prev) {
            return setNestedValue(prev, key, value);
        });
        setUnsavedChanges(true);
    }

    // ---- EXPORT ----

    function handleExport() {
        var output = {
            name: config.name,
            size: config.size,
            speed: config.speed,
            lifetime: config.lifetime,
            colorStart: config.colorStart,
            colorEnd: config.colorEnd,
            fadeOut: config.fadeOut,
            gravity: config.gravity,
            spread: config.spread,
            spawnRate: config.spawnRate,
            direction: config.direction,
            shape: config.shape,
            emitterPosition: emitterPos,
        };
        var json = JSON.stringify(output, null, 2);
        setExportJSON(json);
        setShowExport(true);
    }

    function handleExportAll() {
        var allTemplates = templates.map(function(tpl) {
            return {
                name: tpl.name,
                size: tpl.size,
                speed: tpl.speed,
                lifetime: tpl.lifetime,
                colorStart: tpl.colorStart,
                colorEnd: tpl.colorEnd,
                fadeOut: tpl.fadeOut,
                gravity: tpl.gravity,
                spread: tpl.spread,
                spawnRate: tpl.spawnRate,
                direction: tpl.direction,
                shape: tpl.shape,
            };
        });
        var json = JSON.stringify(allTemplates, null, 2);
        setExportJSON(json);
        setShowExport(true);
    }

    function handleReset() {
        setConfig(deepClone(DEFAULT_CONFIG));
        particlesRef.current = [];
        spawnAccRef.current = 0;
        setEmitterPos({ x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2 });
        setShowExport(false);
        setActiveTemplateIndex(null);
        setUnsavedChanges(false);
    }

    function handleCopyExport() {
        navigator.clipboard.writeText(exportJSON);
    }

    // ---- RENDER PARAM ----

    function renderParam(def) {
        var val = getNestedValue(config, def.key);

        if (def.type === "text") {
            return (
                <div key={def.key} style={styles.paramRow}>
                    <span style={styles.paramLabel}>{def.label}</span>
                    <input
                        style={styles.textInput}
                        value={val}
                        onChange={function(e) { handleParamChange(def.key, e.target.value); }}
                    />
                </div>
            );
        }

        if (def.type === "slider") {
            return (
                <div key={def.key} style={styles.paramRow}>
                    <span style={styles.paramLabel}>{def.label}</span>
                    <input
                        type="range"
                        style={styles.slider}
                        min={def.min}
                        max={def.max}
                        step={def.step}
                        value={val}
                        onChange={function(e) {
                            var v = def.step < 1 ? parseFloat(e.target.value) : parseInt(e.target.value);
                            handleParamChange(def.key, v);
                        }}
                    />
                    <span style={styles.paramValue}>{val}</span>
                </div>
            );
        }

        if (def.type === "color") {
            return (
                <div key={def.key} style={styles.paramRow}>
                    <span style={styles.paramLabel}>{def.label}</span>
                    <input
                        type="color"
                        style={styles.colorInput}
                        value={val}
                        onChange={function(e) { handleParamChange(def.key, e.target.value); }}
                    />
                    <span style={styles.paramValue}>{val}</span>
                </div>
            );
        }

        if (def.type === "toggle") {
            return (
                <div key={def.key} style={styles.paramRow}>
                    <span style={styles.paramLabel}>{def.label}</span>
                    <button
                        style={{
                            ...styles.toggle,
                            background: val ? "#00ffaa" : "#333",
                        }}
                        onClick={function() { handleParamChange(def.key, !val); }}
                    >
                        <div style={{ ...styles.toggleKnob, left: val ? 20 : 2 }} />
                    </button>
                </div>
            );
        }

        if (def.type === "select") {
            return (
                <div key={def.key} style={styles.paramRow}>
                    <span style={styles.paramLabel}>{def.label}</span>
                    <select
                        style={styles.select}
                        value={val}
                        onChange={function(e) { handleParamChange(def.key, e.target.value); }}
                    >
                        {def.options.map(function(opt) {
                            return <option key={opt} value={opt}>{opt}</option>;
                        })}
                    </select>
                </div>
            );
        }

        return null;
    }

    // ============================================
    // RENDER
    // ============================================
    return (
        <div style={styles.container}>

            {/* LEFT — TEMPLATE LIBRARY */}
            <div style={styles.library}>
                <div style={styles.libraryHeader}>
                    Templates ({templates.length})
                </div>

                {templates.map(function(tpl, index) {
                    var isActive = index === activeTemplateIndex;
                    return (
                        <div
                            key={index}
                            style={{
                                ...styles.templateItem,
                                background: isActive ? "#1a1a1a" : "transparent",
                                borderLeft: isActive ? "3px solid #00ffaa" : "3px solid transparent",
                            }}
                            onClick={function() { handleLoadTemplate(index); }}
                        >
                            {/* Color swatch */}
                            <div style={{
                                width: 10,
                                height: 10,
                                borderRadius: 2,
                                background: tpl.colorStart,
                                marginRight: 8,
                                flexShrink: 0,
                            }} />
                            <span style={{
                                ...styles.templateName,
                                color: isActive ? "#00ffaa" : "#aaa",
                            }}>
                                {tpl.name}
                            </span>
                            <div style={styles.templateActions}>
                                <button
                                    style={{ ...styles.templateBtn, color: "#888" }}
                                    onClick={function(e) { e.stopPropagation(); handleDuplicateTemplate(index); }}
                                    title="Duplicate"
                                >
                                    \u2398
                                </button>
                                <button
                                    style={{ ...styles.templateBtn, color: "#ff4444" }}
                                    onClick={function(e) { e.stopPropagation(); handleDeleteTemplate(index); }}
                                    title="Delete"
                                >
                                    \u2715
                                </button>
                            </div>
                        </div>
                    );
                })}

                <button
                    style={styles.addTemplateBtn}
                    onClick={handleNewFromScratch}
                >
                    + New Template
                </button>
            </div>

            {/* CENTER — CANVAS */}
            <div style={styles.canvasWrap}>
                <canvas
                    ref={canvasRef}
                    width={CANVAS_WIDTH}
                    height={CANVAS_HEIGHT}
                    style={styles.canvas}
                    onMouseDown={handleMouseDown}
                    onMouseMove={handleMouseMove}
                    onMouseUp={handleMouseUp}
                    onMouseLeave={handleMouseUp}
                />
                <div style={styles.posLabel}>
                    Emitter: ({emitterPos.x}, {emitterPos.y})
                </div>
                <div style={styles.statusBar}>
                    Particles: {particleCount} / {MAX_PARTICLES}
                    {paused ? " \u23F8 PAUSED" : ""}
                </div>
            </div>

            {/* RIGHT — CONTROLS PANEL */}
            <div style={styles.panel}>
                <div style={styles.panelHeader}>
                    <span>
                        Particle Editor
                        {unsavedChanges && (
                            <span style={{ color: "#f59e0b", marginLeft: 8, fontSize: "9px" }}>\u25CF UNSAVED</span>
                        )}
                    </span>
                    <span
                        style={{ float: "right", cursor: "pointer", color: paused ? "#ff4444" : "#00ffaa" }}
                        onClick={function() { setPaused(!paused); }}
                    >
                        {paused ? "\u25B6 PLAY" : "\u23F8 PAUSE"}
                    </span>
                </div>

                {/* Identity */}
                <div style={styles.section}>
                    <div style={styles.sectionTitle}>Identity</div>
                    {renderParam(PARAM_DEFS[0])}
                </div>

                {/* Emission */}
                <div style={styles.section}>
                    <div style={styles.sectionTitle}>Emission</div>
                    {PARAM_DEFS.slice(1, 2).map(renderParam)}
                </div>

                {/* Size */}
                <div style={styles.section}>
                    <div style={styles.sectionTitle}>Size</div>
                    {PARAM_DEFS.slice(2, 4).map(renderParam)}
                </div>

                {/* Motion */}
                <div style={styles.section}>
                    <div style={styles.sectionTitle}>Motion</div>
                    {PARAM_DEFS.slice(4, 11).map(renderParam)}
                </div>

                {/* Appearance */}
                <div style={styles.section}>
                    <div style={styles.sectionTitle}>Appearance</div>
                    {PARAM_DEFS.slice(11).map(renderParam)}
                </div>

                {/* Save / Actions */}
                <div style={styles.section}>
                    <div style={styles.sectionTitle}>Save</div>
                    <button
                        style={{
                            ...styles.exportBtn,
                            background: unsavedChanges ? "#f59e0b" : "#00ffaa",
                        }}
                        onClick={handleSaveTemplate}
                    >
                        {activeTemplateIndex !== null ? "Save Template" : "Save as New Template"}
                    </button>
                    {activeTemplateIndex !== null && (
                        <button style={styles.resetBtn} onClick={handleSaveAsNew}>
                            Save as Copy
                        </button>
                    )}
                </div>

                {/* Export */}
                <div style={styles.section}>
                    <div style={styles.sectionTitle}>Export</div>
                    <button style={styles.exportBtn} onClick={handleExport}>
                        Export Current
                    </button>
                    <button
                        style={{ ...styles.exportBtn, background: "#f59e0b", marginTop: 4 }}
                        onClick={handleExportAll}
                    >
                        Export All Templates
                    </button>
                    <button style={styles.resetBtn} onClick={handleReset}>
                        Reset All
                    </button>
                    {showExport && (
                        <div>
                            <textarea
                                style={styles.exportArea}
                                value={exportJSON}
                                readOnly
                                rows={8}
                            />
                            <button
                                style={{ ...styles.resetBtn, marginTop: 4, color: "#00ffaa", borderColor: "#00ffaa" }}
                                onClick={handleCopyExport}
                            >
                                Copy to Clipboard
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

export default ParticleEditor;